mapper.select:
SELECT cb.id, cb.card_id, bc.card_no_last4, bc.bank_name, bc.owner_relation, cb.owner_id, cu.name AS owner_name, cb.bill_month, cb.bill_day, cb.bill_amount, cb.min_pay_amount, cb.repay_date, DAY(cb.repay_date) AS repay_day, cb.actual_pay_amount, cb.actual_pay_date, cb.status, cb.remark, cb.fee_rate, cb.fee_amount, cb.pos_cost_amount, cb.net_profit, bc.repay_method, cb.create_time FROM card_bill cb LEFT JOIN bank_card bc ON bc.id = cb.card_id AND bc.is_deleted = 0 LEFT JOIN card_user cu ON cu.id = cb.owner_id AND cu.is_deleted = 0 WHERE cb.is_deleted = 0 AND cb.card_id = #{cardId} AND cb.owner_id = #{ownerId}
AND ( bc.bank_name LIKE CONCAT('%', #{cardName}, '%') OR bc.card_no_last4 LIKE CONCAT('%', #{cardName}, '%') )
AND cb.bill_month = #{billMonth} AND LEFT(cb.bill_month, 4) = #{year} AND cb.status = #{status}
ORDER BY cb.bill_month ASC, cb.create_time ASC
ORDER BY cb.bill_month DESC, cb.create_time DESC

SELECT COUNT(1) AS billCount, SUM(CASE WHEN cb.status = 0 THEN 1 ELSE 0 END) AS pendingCount, SUM(CASE WHEN cb.status = 1 THEN 1 ELSE 0 END) AS repaidCount, SUM(CASE WHEN cb.status = 2 THEN 1 ELSE 0 END) AS partialCount, SUM(CASE WHEN cb.status = 3 THEN 1 ELSE 0 END) AS overdueCount, IFNULL(SUM(cb.bill_amount), 0) AS totalBillAmount, IFNULL(SUM(cb.fee_amount), 0) AS totalFeeAmount, IFNULL(SUM(cb.pos_cost_amount), 0) AS totalPosCostAmount, IFNULL(SUM(cb.net_profit), 0) AS totalNetProfit FROM card_bill cb LEFT JOIN bank_card bc ON bc.id = cb.card_id AND bc.is_deleted = 0 LEFT JOIN card_user cu ON cu.id = cb.owner_id AND cu.is_deleted = 0 WHERE cb.is_deleted = 0 AND cb.card_id = #{cardId} AND cb.owner_id = #{ownerId}
AND ( bc.bank_name LIKE CONCAT('%', #{cardName}, '%') OR bc.card_no_last4 LIKE CONCAT('%', #{cardName}, '%') )
AND cb.bill_month = #{billMonth} AND LEFT(cb.bill_month, 4) = #{year} AND cb.status = #{status}
